changeSet.sql:
ALTER TABLE public.spell
    ADD COLUMN IF NOT EXISTS origin_mode varchar(16) NOT NULL DEFAULT 'NEW',
    ADD COLUMN IF NOT EXISTS origin_source_id uuid;
ALTER TABLE public.magic_item
    ADD COLUMN IF NOT EXISTS origin_mode varchar(16) NOT NULL DEFAULT 'NEW',
    ADD COLUMN IF NOT EXISTS origin_source_id uuid;
ALTER TABLE public.equipment_item
    ADD COLUMN IF NOT EXISTS origin_mode varchar(16) NOT NULL DEFAULT 'NEW',
    ADD COLUMN IF NOT EXISTS origin_source_id uuid;

CREATE INDEX IF NOT EXISTS idx_spell_origin_source ON public.spell (origin_source_id) WHERE origin_source_id IS NOT NULL;
CREATE INDEX IF NOT EXISTS idx_magic_item_origin_source ON public.magic_item (origin_source_id) WHERE origin_source_id IS NOT NULL;
CREATE INDEX IF NOT EXISTS idx_equipment_item_origin_source ON public.equipment_item (origin_source_id) WHERE origin_source_id IS NOT NULL;

rollback.sql:
DROP INDEX IF EXISTS idx_spell_origin_source;
DROP INDEX IF EXISTS idx_magic_item_origin_source;
DROP INDEX IF EXISTS idx_equipment_item_origin_source;
ALTER TABLE public.spell DROP COLUMN IF EXISTS origin_mode, DROP COLUMN IF EXISTS origin_source_id;
ALTER TABLE public.magic_item DROP COLUMN IF EXISTS origin_mode, DROP COLUMN IF EXISTS origin_source_id;
ALTER TABLE public.equipment_item DROP COLUMN IF EXISTS origin_mode, DROP COLUMN IF EXISTS origin_source_id;
